#!/usr/bin/env python3
"""
encode-molmo.py — encode allenai/MolmoAct2-Think weights into a .knot file
containing the Qwen3-style LM backbone + custom ViT + vision adapter
(image_pooling_2d + image_projector) + the flow-matching action expert.

Usage:
    python encode-molmo.py \
        --model allenai/MolmoAct2-Think \
        --out molmoact2-think-vlm.knot \
        [--hf-token YOUR_HF_TOKEN]

The output .knot file packs every sub-model under one flat tensor namespace:

  LM    : token_embd_weight, output_norm_weight, output_weight, blk_*_*  (qwen3)
  ViT   : vit_patch_emb_*, vit_pos_emb_weight, vit_blk_*_*
  ADAPT : adapter_attn_*, adapter_proj_*  (attention pooling + SwiGLU projector)
  ACTION: ae_*  (per-LM-layer flow-matching DiT denoiser)

The top-level KnotConfig.arch is "qwen3" so NativeLlamaPipeline wires the
Qwen3 QK-norm / GQA path for the text backbone. A nested "molmo_config" block
carries the ViT / adapter / action-expert / text sub-configs (mirrors the Rust
`MolmoAct2Config` in model_molmoact2_config.rs).

Tensor names were derived from the ACTUAL checkpoint weight_map (sf_index.json)
and the modeling source (modeling_molmoact2.py), NOT from generic HF defaults.

Dependencies:
    pip install torch transformers safetensors huggingface_hub
"""

import argparse
import json
import os
import re
import struct
import sys
from pathlib import Path

import torch
from safetensors.torch import load_file as st_load
from huggingface_hub import snapshot_download


# ─── Architecture constants (from the real checkpoint) ──────────────────────

# Text backbone (Qwen3-style decoder).
LM_HIDDEN = 2560
LM_LAYERS = 36
LM_HEADS = 32
LM_KV_HEADS = 8
LM_HEAD_DIM = 128
LM_INTERMEDIATE = 9728           # per-half of ff_proj (gate==up==9728)
LM_VOCAB = 155648                # full vocab incl. new_embedding rows
LM_RMS_EPS = 1e-6
LM_ROPE_THETA = 5_000_000.0

# att_proj fused split: rows [q | k | v].
#   q = num_heads * head_dim   = 32 * 128 = 4096
#   k = num_kv_heads * head_dim =  8 * 128 = 1024
#   v = num_kv_heads * head_dim =  8 * 128 = 1024  (total 6144)
LM_Q_DIM = LM_HEADS * LM_HEAD_DIM        # 4096
LM_KV_DIM = LM_KV_HEADS * LM_HEAD_DIM    # 1024

# ViT (custom SigLIP-style encoder, 25 resblocks).
VIT_HIDDEN = 1152
VIT_LAYERS = 25
VIT_HEADS = 16
VIT_INTERMEDIATE = 4304
VIT_IMAGE_SIZE = 378
VIT_PATCH_SIZE = 14
VIT_LN_EPS = 1e-6
VIT_EXTRACT_LAYERS = [-3, -9]

# Vision adapter (image_pooling_2d + image_projector).
ADAPTER_HIDDEN = 1152
ADAPTER_INPUT_DIM = VIT_HIDDEN * len(VIT_EXTRACT_LAYERS)   # 2304 (pool_dim)
ADAPTER_HEADS = 16
ADAPTER_INTERMEDIATE = 9728        # image_projector inner SwiGLU dim
ADAPTER_TEXT_HIDDEN = LM_HIDDEN    # 2560
ADAPTER_NUM_QUERY = 729            # one pooled token per high-res patch group

# Action expert (per-LM-layer flow-matching DiT denoiser).
AE_HIDDEN = 768
AE_LAYERS = 36                     # one block per LM layer
AE_HEADS = 8
AE_MLP_RATIO = 4.0
AE_FFN_MULTIPLE_OF = 256
AE_TIMESTEP_EMBED_DIM = 256
AE_QK_NORM_EPS = 1e-6
AE_ROPE_THETA = 10_000.0
AE_LLM_KV_DIM = LM_KV_DIM          # 1024 (LM K/V dim fed into cross-attn)
AE_MAX_ACTION_HORIZON = 30
AE_MAX_ACTION_DIM = 32
AE_FLOW_MATCHING_NUM_STEPS = 10


# ─── HF tensor name → knot tensor name mappings ─────────────────────────────
#
# These are SIMPLE 1:1 / passthrough maps.  Tensors that need to be SPLIT or
# CONCATENATED (att_proj, ff_proj, wte) are handled imperatively in
# build_knot_tensors() because they consume/produce multiple tensors.

def lm_simple_map(hf_name: str) -> str | None:
    """Map 1:1 HF Qwen3 text-backbone tensor names → knot names.

    Fused / concatenated tensors (att_proj, ff_proj, wte.embedding +
    wte.new_embedding) are NOT handled here — see build_knot_tensors().
    """
    n = hf_name
    if n == "model.transformer.ln_f.weight":
        return "output_norm_weight"
    if n == "lm_head.weight":
        return "output_weight"
    m = re.match(r"model\.transformer\.blocks\.(\d+)\.(.*)", n)
    if not m:
        return None
    i, rest = int(m.group(1)), m.group(2)
    table = {
        "attn_norm.weight":            f"blk_{i}_attn_norm_weight",
        "ff_norm.weight":              f"blk_{i}_ffn_norm_weight",
        "self_attn.attn_out.weight":   f"blk_{i}_attn_output_weight",
        "self_attn.q_norm.weight":     f"blk_{i}_attn_q_norm_weight",
        "self_attn.k_norm.weight":     f"blk_{i}_attn_k_norm_weight",
        "mlp.ff_out.weight":           f"blk_{i}_ffn_down_weight",
    }
    return table.get(rest)


def vit_simple_map(hf_name: str) -> str | None:
    """Map HF MolmoAct2 ViT tensor names → knot vit_* names (all 1:1)."""
    n = hf_name
    base = "model.vision_backbone.image_vit."
    if n == base + "patch_embedding.weight":
        return "vit_patch_emb_weight"
    if n == base + "patch_embedding.bias":
        return "vit_patch_emb_bias"
    # positional_embedding is a bare nn.Parameter (no .weight suffix).
    if n == base + "positional_embedding":
        return "vit_pos_emb_weight"
    m = re.match(
        r"model\.vision_backbone\.image_vit\.transformer\.resblocks\.(\d+)\.(.*)",
        n,
    )
    if not m:
        return None
    i, rest = int(m.group(1)), m.group(2)
    table = {
        # attention_norm == pre-attention LayerNorm (knot ln1).
        "attention_norm.weight":   f"vit_blk_{i}_ln1_weight",
        "attention_norm.bias":     f"vit_blk_{i}_ln1_bias",
        "attention.wq.weight":     f"vit_blk_{i}_attn_q_weight",
        "attention.wq.bias":       f"vit_blk_{i}_attn_q_bias",
        "attention.wk.weight":     f"vit_blk_{i}_attn_k_weight",
        "attention.wk.bias":       f"vit_blk_{i}_attn_k_bias",
        "attention.wv.weight":     f"vit_blk_{i}_attn_v_weight",
        "attention.wv.bias":       f"vit_blk_{i}_attn_v_bias",
        "attention.wo.weight":     f"vit_blk_{i}_attn_out_weight",
        "attention.wo.bias":       f"vit_blk_{i}_attn_out_bias",
        # ffn_norm == pre-FFN LayerNorm (knot ln2).
        "ffn_norm.weight":         f"vit_blk_{i}_ln2_weight",
        "ffn_norm.bias":           f"vit_blk_{i}_ln2_bias",
        "feed_forward.w1.weight":  f"vit_blk_{i}_mlp_fc1_weight",
        "feed_forward.w1.bias":    f"vit_blk_{i}_mlp_fc1_bias",
        "feed_forward.w2.weight":  f"vit_blk_{i}_mlp_fc2_weight",
        "feed_forward.w2.bias":    f"vit_blk_{i}_mlp_fc2_bias",
    }
    return table.get(rest)


def adapter_simple_map(hf_name: str) -> str | None:
    """Map HF MolmoAct2 vision-adapter tensor names → knot adapter_* names.

    image_pooling_2d is a ViTMultiHeadDotProductAttention whose QUERY is the
    (masked) mean of the patch group it pools — there is NO learnable query
    parameter.  wq/wk/wv all project from pool_dim (input_dim=2304); wo maps
    n_heads*head_dim → adapter hidden_size.  All four carry a bias.

    image_projector is a SwiGLU: out = w2(silu(w1(x)) * w3(x))
      → w1 = gate, w3 = up, w2 = down.
    """
    n = hf_name
    pool = "model.vision_backbone.image_pooling_2d."
    proj = "model.vision_backbone.image_projector."
    if n.startswith(pool):
        rest = n[len(pool):]
        return {
            "wq.weight":   "adapter_attn_q_weight",
            "wq.bias":     "adapter_attn_q_bias",
            "wk.weight":   "adapter_attn_k_weight",
            "wk.bias":     "adapter_attn_k_bias",
            "wv.weight":   "adapter_attn_v_weight",
            "wv.bias":     "adapter_attn_v_bias",
            "wo.weight":   "adapter_attn_out_weight",
            "wo.bias":     "adapter_attn_out_bias",
        }.get(rest)
    if n.startswith(proj):
        rest = n[len(proj):]
        return {
            "w1.weight":   "adapter_proj_gate_weight",   # silu(w1·x) gate
            "w3.weight":   "adapter_proj_up_weight",      # up path
            "w2.weight":   "adapter_proj_down_weight",    # down projection
        }.get(rest)
    return None


def action_expert_map(hf_name: str) -> str | None:
    """Map HF MolmoAct2 action-expert tensor names → knot ae_* names.

    All RMSNorms inside the action expert are WEIGHTLESS (elementwise_affine
    = False), so no norm tensors appear in the checkpoint and none are mapped.
    The depth gate / FAST action tokenizer tensors are intentionally not used.
    """
    n = hf_name
    prefix = "model.action_expert."
    if not n.startswith(prefix):
        return None
    rest = n[len(prefix):]
    top = {
        "action_embed.weight":             "ae_action_embed_weight",
        "action_embed.bias":               "ae_action_embed_bias",
        # time_embed is an nn.Sequential: [Sinusoidal, Linear(1), SiLU, Linear(3)]
        "time_embed.1.weight":             "ae_time1_weight",
        "time_embed.1.bias":               "ae_time1_bias",
        "time_embed.3.weight":             "ae_time3_weight",
        "time_embed.3.bias":               "ae_time3_bias",
        "context_k_proj.weight":           "ae_ctx_k_weight",
        "context_v_proj.weight":           "ae_ctx_v_weight",
        "final_layer.linear.weight":       "ae_final_linear_weight",
        "final_layer.linear.bias":         "ae_final_linear_bias",
        "final_layer.modulation.linear.weight": "ae_final_mod_weight",
        "final_layer.modulation.linear.bias":   "ae_final_mod_bias",
    }
    if rest in top:
        return top[rest]
    m = re.match(r"blocks\.(\d+)\.(.*)", rest)
    if not m:
        return None
    i, sub = int(m.group(1)), m.group(2)
    table = {
        "self_attn.qkv.weight":      f"ae_blk_{i}_sa_qkv_weight",
        "self_attn.qkv.bias":        f"ae_blk_{i}_sa_qkv_bias",
        "self_attn.out_proj.weight": f"ae_blk_{i}_sa_out_weight",
        "self_attn.out_proj.bias":   f"ae_blk_{i}_sa_out_bias",
        "cross_attn.q_proj.weight":  f"ae_blk_{i}_ca_q_weight",
        "cross_attn.q_proj.bias":    f"ae_blk_{i}_ca_q_bias",
        "cross_attn.out_proj.weight": f"ae_blk_{i}_ca_out_weight",
        "cross_attn.out_proj.bias":   f"ae_blk_{i}_ca_out_bias",
        "mlp.gate_proj.weight":      f"ae_blk_{i}_mlp_gate_weight",
        "mlp.gate_proj.bias":        f"ae_blk_{i}_mlp_gate_bias",
        "mlp.up_proj.weight":        f"ae_blk_{i}_mlp_up_weight",
        "mlp.up_proj.bias":          f"ae_blk_{i}_mlp_up_bias",
        "mlp.down_proj.weight":      f"ae_blk_{i}_mlp_down_weight",
        "mlp.down_proj.bias":        f"ae_blk_{i}_mlp_down_bias",
        "modulation.linear.weight":  f"ae_blk_{i}_mod_weight",
        "modulation.linear.bias":    f"ae_blk_{i}_mod_bias",
    }
    return table.get(sub)


# Tensors we deliberately drop (depth gate / FAST tokenizer / rope caches /
# anything not consumed by the runtime).  Used only for cleaner reporting.
_IGNORE_SUBSTRINGS = (
    "rotary_emb.inv_freq",   # recomputed at runtime from rope_theta
)


# ─── Tensor build (handles fused splits + concatenations) ───────────────────

def build_knot_tensors(
    all_tensors: dict[str, torch.Tensor]
) -> tuple[dict[str, torch.Tensor], list[str]]:
    """Produce the full knot tensor namespace.

    Returns (knot_tensors, unmapped_hf_names).
    """
    knot: dict[str, torch.Tensor] = {}
    unmapped: list[str] = []
    consumed: set[str] = set()

    def f32(t: torch.Tensor) -> torch.Tensor:
        return t.to(torch.float32).contiguous()

    # ── LM token embedding: cat([wte.embedding, wte.new_embedding]) ──────────
    emb = all_tensors.get("model.transformer.wte.embedding")
    new_emb = all_tensors.get("model.transformer.wte.new_embedding")
    if emb is not None:
        consumed.add("model.transformer.wte.embedding")
        if new_emb is not None:
            consumed.add("model.transformer.wte.new_embedding")
            full = torch.cat([f32(emb), f32(new_emb)], dim=0)
        else:
            full = f32(emb)
        knot["token_embd_weight"] = full

    # ── LM per-block fused att_proj split → q / k / v ────────────────────────
    for i in range(LM_LAYERS):
        att = all_tensors.get(
            f"model.transformer.blocks.{i}.self_attn.att_proj.weight"
        )
        if att is not None:
            consumed.add(
                f"model.transformer.blocks.{i}.self_attn.att_proj.weight"
            )
            att = f32(att)  # [6144, 2560]
            q = att[0:LM_Q_DIM]                              # [4096, 2560]
            k = att[LM_Q_DIM:LM_Q_DIM + LM_KV_DIM]           # [1024, 2560]
            v = att[LM_Q_DIM + LM_KV_DIM:
                    LM_Q_DIM + 2 * LM_KV_DIM]                # [1024, 2560]
            knot[f"blk_{i}_attn_q_weight"] = q.contiguous()
            knot[f"blk_{i}_attn_k_weight"] = k.contiguous()
            knot[f"blk_{i}_attn_v_weight"] = v.contiguous()

        # ── LM fused ff_proj split → up / gate ──────────────────────────────
        # modeling: x = ff_proj(x); x, gate = x.chunk(2); out = silu(gate)*x
        #   rows [0:9728]      = x    → UP
        #   rows [9728:19456]  = gate → GATE
        ff = all_tensors.get(
            f"model.transformer.blocks.{i}.mlp.ff_proj.weight"
        )
        if ff is not None:
            consumed.add(f"model.transformer.blocks.{i}.mlp.ff_proj.weight")
            ff = f32(ff)  # [19456, 2560]
            up = ff[0:LM_INTERMEDIATE]                       # [9728, 2560]
            gate = ff[LM_INTERMEDIATE:2 * LM_INTERMEDIATE]   # [9728, 2560]
            knot[f"blk_{i}_ffn_up_weight"] = up.contiguous()
            knot[f"blk_{i}_ffn_gate_weight"] = gate.contiguous()

    # ── Everything else via the 1:1 mappers ─────────────────────────────────
    for hf_name, t in all_tensors.items():
        if hf_name in consumed:
            continue
        knot_name = (
            lm_simple_map(hf_name)
            or vit_simple_map(hf_name)
            or adapter_simple_map(hf_name)
            or action_expert_map(hf_name)
        )
        if knot_name is not None:
            knot[knot_name] = f32(t)
        elif any(s in hf_name for s in _IGNORE_SUBSTRINGS):
            continue
        else:
            unmapped.append(hf_name)

    return knot, unmapped


def verify_completeness(knot: dict[str, torch.Tensor]) -> list[str]:
    """Verify every required per-block tensor exists. Returns list of misses."""
    misses: list[str] = []

    def need(name: str):
        if name not in knot:
            misses.append(name)

    # LM globals.
    for g in ("token_embd_weight", "output_norm_weight", "output_weight"):
        need(g)
    # LM blocks.
    lm_block_keys = (
        "attn_norm_weight", "attn_q_weight", "attn_k_weight", "attn_v_weight",
        "attn_output_weight", "attn_q_norm_weight", "attn_k_norm_weight",
        "ffn_norm_weight", "ffn_gate_weight", "ffn_up_weight", "ffn_down_weight",
    )
    for i in range(LM_LAYERS):
        for k in lm_block_keys:
            need(f"blk_{i}_{k}")

    # ViT globals.
    for g in ("vit_patch_emb_weight", "vit_patch_emb_bias", "vit_pos_emb_weight"):
        need(g)
    vit_block_keys = (
        "ln1_weight", "ln1_bias", "attn_q_weight", "attn_q_bias",
        "attn_k_weight", "attn_k_bias", "attn_v_weight", "attn_v_bias",
        "attn_out_weight", "attn_out_bias", "ln2_weight", "ln2_bias",
        "mlp_fc1_weight", "mlp_fc1_bias", "mlp_fc2_weight", "mlp_fc2_bias",
    )
    for i in range(VIT_LAYERS):
        for k in vit_block_keys:
            need(f"vit_blk_{i}_{k}")

    # Adapter.
    for g in (
        "adapter_attn_q_weight", "adapter_attn_q_bias",
        "adapter_attn_k_weight", "adapter_attn_k_bias",
        "adapter_attn_v_weight", "adapter_attn_v_bias",
        "adapter_attn_out_weight", "adapter_attn_out_bias",
        "adapter_proj_gate_weight", "adapter_proj_up_weight",
        "adapter_proj_down_weight",
    ):
        need(g)

    # Action expert globals.
    for g in (
        "ae_action_embed_weight", "ae_action_embed_bias",
        "ae_time1_weight", "ae_time1_bias", "ae_time3_weight", "ae_time3_bias",
        "ae_ctx_k_weight", "ae_ctx_v_weight",
        "ae_final_linear_weight", "ae_final_linear_bias",
        "ae_final_mod_weight", "ae_final_mod_bias",
    ):
        need(g)
    ae_block_keys = (
        "sa_qkv_weight", "sa_qkv_bias", "sa_out_weight", "sa_out_bias",
        "ca_q_weight", "ca_q_bias", "ca_out_weight", "ca_out_bias",
        "mlp_gate_weight", "mlp_gate_bias", "mlp_up_weight", "mlp_up_bias",
        "mlp_down_weight", "mlp_down_bias", "mod_weight", "mod_bias",
    )
    for i in range(AE_LAYERS):
        for k in ae_block_keys:
            need(f"ae_blk_{i}_{k}")

    return misses


# ─── Knot serialization ──────────────────────────────────────────────────────

def tensor_to_bytes(t: torch.Tensor) -> bytes:
    return t.to(torch.float32).contiguous().cpu().numpy().tobytes()


# ── Q8_0 quantization for the LM's big projection matrices ───────────────────
# The 5B F32 LM is ~20 GB — too big for Cloud Run's 32 GiB cap. Q8_0 (8-bit,
# near-lossless, the quant every other mesh model uses) shrinks the per-block
# attn/ffn matrices ~4x. Embeddings, lm_head, norms, and ALL VLM tensors (ViT /
# adapter / action-expert, whose Rust readers assume f32) stay F32. The runtime
# resolves the per-tensor "type" field and dequantizes Q8_0 in mat_vec.
# Layout MUST match math.rs mat_vec_q8_0_row: 34-byte blocks = 2-byte LE fp16
# scale + 32 i8. All LM matrices have cols % 32 == 0, so blocks are row-aligned.
import numpy as _np

Q8_0_BLOCK = 32
_Q8_RE = re.compile(r"^blk_\d+_(attn_(q|k|v|output)|ffn_(gate|up|down))_weight$")


def _is_q8(name: str) -> bool:
    return bool(_Q8_RE.match(name))


def _q8_len(numel: int) -> int:
    n_blocks = (numel + Q8_0_BLOCK - 1) // Q8_0_BLOCK
    return n_blocks * 34


def _q8_0_encode(arr: "_np.ndarray") -> bytes:
    arr = arr.astype(_np.float32).flatten()
    pad = (-len(arr)) % Q8_0_BLOCK
    if pad:
        arr = _np.pad(arr, (0, pad))
    blocks = arr.reshape(-1, Q8_0_BLOCK)
    amax = _np.abs(blocks).max(axis=1)
    d = amax / 127.0
    with _np.errstate(divide="ignore", invalid="ignore"):
        inv = _np.where(d > 0.0, 1.0 / d, 0.0)
    q = _np.clip(_np.round(blocks * inv[:, None]), -127, 127).astype(_np.int8)
    d16 = d.astype(_np.float16)
    out = _np.empty((blocks.shape[0], 2 + Q8_0_BLOCK), dtype=_np.uint8)
    out[:, :2] = d16.view(_np.uint8).reshape(-1, 2)
    out[:, 2:] = q.view(_np.uint8)
    return out.tobytes()


def write_knot(out_path: str, tensors: dict[str, torch.Tensor], config: dict):
    """Write tensors + config to a .knot file."""
    MAGIC = b"KNOT"
    VERSION = 1

    # Pass 1: compute offsets/lengths from SHAPES only (no byte materialization),
    # so we never hold the full ~20 GB payload in RAM (would OOM the 32 GB builder).
    tensor_meta = {}
    offset = 0
    names = list(tensors.keys())
    for name in names:
        numel = tensors[name].numel()
        if _is_q8(name):
            length = _q8_len(numel)
            ttype = "Q8_0"
        else:
            length = numel * 4
            ttype = "fp32"
        tensor_meta[name] = {"offset": offset, "length": length, "type": ttype}
        offset += length

    metadata = {
        "name": "molmoact2-think-vlm",
        "codec": "fp32",
        "topology": "attention-mesh",
        "config": config,
        "tensors": tensor_meta,
    }
    meta_json = json.dumps(metadata, separators=(",", ":")).encode("utf-8")
    meta_len = len(meta_json)

    # Pad metadata to 4-byte alignment.
    pad = (4 - (10 + meta_len) % 4) % 4
    header = MAGIC + struct.pack("<HI", VERSION, meta_len) + meta_json + b"\x00" * pad
    # Codec marker (0 = fp32).
    header += bytes([0])

    # Pass 2: stream each tensor to disk one at a time, freeing it from the dict
    # immediately so peak memory stays ~one tensor above the resident weight set.
    n = len(names)
    n_q8 = 0
    with open(out_path, "wb") as f:
        f.write(header)
        for name in names:
            t = tensors.pop(name)
            if _is_q8(name):
                data = _q8_0_encode(t.to(torch.float32).contiguous().cpu().numpy())
                n_q8 += 1
            else:
                data = tensor_to_bytes(t)
            # Length must match the offset computed in pass 1.
            assert len(data) == tensor_meta[name]["length"], (
                f"{name}: wrote {len(data)} bytes, header says {tensor_meta[name]['length']}"
            )
            f.write(data)
            del t
    print(f"Written {out_path} ({os.path.getsize(out_path) / 1e9:.2f} GB, "
          f"{n} tensors, {n_q8} Q8_0)")


def build_config() -> dict:
    """Build the top-level KnotConfig + nested molmo_config block.

    Top-level keys drive NativeLlamaPipeline (arch="qwen3" → QK-norm + GQA).
    The nested "molmo_config" mirrors the Rust MolmoAct2Config sub-configs.
    """
    text_config = {
        "hidden_size": LM_HIDDEN,
        "num_hidden_layers": LM_LAYERS,
        "num_attention_heads": LM_HEADS,
        "num_key_value_heads": LM_KV_HEADS,
        "head_dim": LM_HEAD_DIM,
        "intermediate_size": LM_INTERMEDIATE,
        "vocab_size": LM_VOCAB,
        "rms_norm_eps": LM_RMS_EPS,
        "rope_theta": LM_ROPE_THETA,
        "tie_word_embeddings": False,
    }
    vit_config = {
        "hidden_size": VIT_HIDDEN,
        "num_hidden_layers": VIT_LAYERS,
        "num_attention_heads": VIT_HEADS,
        "intermediate_size": VIT_INTERMEDIATE,
        "image_size": VIT_IMAGE_SIZE,
        "patch_size": VIT_PATCH_SIZE,
        "layer_norm_eps": VIT_LN_EPS,
        "extract_layers": VIT_EXTRACT_LAYERS,
    }
    adapter_config = {
        "hidden_size": ADAPTER_HIDDEN,
        "input_dim": ADAPTER_INPUT_DIM,
        "num_attention_heads": ADAPTER_HEADS,
        "intermediate_size": ADAPTER_INTERMEDIATE,
        "text_hidden_size": ADAPTER_TEXT_HIDDEN,
        "num_query_tokens": ADAPTER_NUM_QUERY,
        "layer_norm_eps": VIT_LN_EPS,
    }
    action_expert_config = {
        "hidden_size": AE_HIDDEN,
        "num_layers": AE_LAYERS,
        "num_heads": AE_HEADS,
        "mlp_ratio": AE_MLP_RATIO,
        "ffn_multiple_of": AE_FFN_MULTIPLE_OF,
        "timestep_embed_dim": AE_TIMESTEP_EMBED_DIM,
        "qk_norm_eps": AE_QK_NORM_EPS,
        "rope_theta": AE_ROPE_THETA,
        "llm_kv_dim": AE_LLM_KV_DIM,
        "max_action_horizon": AE_MAX_ACTION_HORIZON,
        "max_action_dim": AE_MAX_ACTION_DIM,
        "flow_matching_num_steps": AE_FLOW_MATCHING_NUM_STEPS,
    }

    config = {
        # ── Top-level: drives NativeLlamaPipeline (qwen3 text backbone) ──────
        "arch": "qwen3",
        "hidden_dim": LM_HIDDEN,
        "num_layers": LM_LAYERS,
        "num_heads": LM_HEADS,
        "num_kv_heads": LM_KV_HEADS,
        "head_dim": LM_HEAD_DIM,
        "intermediate_size": LM_INTERMEDIATE,
        "vocab_size": LM_VOCAB,
        "rms_norm_eps": LM_RMS_EPS,
        "rope_theta": LM_ROPE_THETA,
        "tie_word_embeddings": False,
        # Marks this knot as a MolmoAct2 VLM bundle for the pipeline dispatcher.
        "model_family": "molmoact2",
        # ── Nested: mirrors Rust MolmoAct2Config (model_molmoact2_config.rs) ─
        "molmo_config": {
            "text_config": text_config,
            "vit_config": vit_config,
            "adapter_config": adapter_config,
            "action_expert_config": action_expert_config,
        },
    }
    return config


# ─── Main ────────────────────────────────────────────────────────────────────

def main():
    parser = argparse.ArgumentParser(description="Encode MolmoAct2-Think → VLM .knot")
    parser.add_argument("--model", default="allenai/MolmoAct2-Think",
                        help="HuggingFace model ID or local path")
    parser.add_argument("--out", default="molmoact2-think-vlm.knot",
                        help="Output .knot file path")
    parser.add_argument("--hf-token", default=None,
                        help="HuggingFace token for gated repos")
    args = parser.parse_args()

    # Download model files.
    if Path(args.model).exists():
        model_dir = args.model
    else:
        print(f"Downloading {args.model} from HuggingFace…")
        model_dir = snapshot_download(
            args.model,
            token=args.hf_token,
            ignore_patterns=["*.msgpack", "*.h5", "flax_model*"],
        )
    print(f"Model dir: {model_dir}")

    # Load all safetensors shards.
    index_path = Path(model_dir) / "model.safetensors.index.json"
    if index_path.exists():
        with open(index_path) as f:
            index = json.load(f)
        shard_files = sorted(set(index["weight_map"].values()))
    else:
        shard_files = ["model.safetensors"]

    all_tensors: dict[str, torch.Tensor] = {}
    for shard in shard_files:
        path = Path(model_dir) / shard
        if not path.exists():
            print(f"Skipping missing shard: {shard}", file=sys.stderr)
            continue
        print(f"  Loading shard {shard}…")
        shard_data = st_load(str(path), device="cpu")
        all_tensors.update(shard_data)
    print(f"Loaded {len(all_tensors)} tensors total")

    # Map (split / concat / 1:1) to the knot namespace.
    knot_tensors, unmapped = build_knot_tensors(all_tensors)

    if unmapped:
        print(f"Unmapped (skipped) {len(unmapped)} HF tensors:")
        for s in unmapped[:30]:
            print(f"  {s}")
        if len(unmapped) > 30:
            print(f"  … and {len(unmapped) - 30} more")

    # Verify required tensors are all present (no None drops for 0..35 etc.).
    misses = verify_completeness(knot_tensors)
    if misses:
        print(f"ERROR: {len(misses)} required knot tensors are MISSING:",
              file=sys.stderr)
        for m in misses[:40]:
            print(f"  {m}", file=sys.stderr)
        if len(misses) > 40:
            print(f"  … and {len(misses) - 40} more", file=sys.stderr)
        sys.exit(1)
    print(f"Completeness check passed: all required tensors present "
          f"({len(knot_tensors)} total)")

    config = build_config()
    write_knot(args.out, knot_tensors, config)


if __name__ == "__main__":
    main()
